import React, { useState, useCallback } from 'react';
import { useUser } from './hooks/useUser';
import { useFormThread } from './hooks/useFormThread';
import AuthPage from './components/AuthPage';
import Sidebar from './components/Sidebar';
import QuestionList from './components/QuestionList';
import ThreadView from './components/ThreadView';

// ── Route guard + role-based shell ────────────────────────────────────────────

function Dashboard() {
  const { user, logout, isAdmin } = useUser();
  const [lastNewMessageId, setLastNewMessageId] = useState<string | null>(null);

  const {
    forms,
    visibleQuestions,
    allQuestions,
    selectedForm,
    selectedQuestion,
    selectedFormId,
    selectedQuestionId,
    activeTab,
    setActiveTab,
    selectForm,
    selectQuestion,
    sendReply,
    unreadCount,
  } = useFormThread();

  const handleSendReply = useCallback(
    (questionId: string, content: string) => {
      const newId = `m-${Date.now()}`;
      sendReply(questionId, content);
      setLastNewMessageId(newId);
      setTimeout(() => setLastNewMessageId(null), 500);
    },
    [sendReply]
  );

  // Role-based form filtering:
  // Admin → sees all forms
  // Participant → only forms assigned to their email
  const visibleForms = isAdmin
    ? forms
    : forms.filter((f) => user!.assignedFormIds.includes(f.id));

  const allFormQuestions = allQuestions.filter((q) => q.formId === selectedFormId);

  return (
    <div className="relative z-10 h-screen flex overflow-hidden">
      <Sidebar
        forms={visibleForms}
        allQuestions={allQuestions}
        selectedFormId={selectedFormId}
        onSelectForm={selectForm}
        unreadCount={unreadCount}
        user={user!}
        onLogout={logout}
      />

      <QuestionList
        form={selectedForm}
        questions={visibleQuestions}
        allFormQuestions={allFormQuestions}
        selectedQuestionId={selectedQuestionId}
        activeTab={activeTab}
        onSelectQuestion={selectQuestion}
        onTabChange={setActiveTab}
      />

      <ThreadView
        question={selectedQuestion}
        form={selectedForm}
        onSendReply={handleSendReply}
        newMessageId={lastNewMessageId}
        user={user!}
      />
    </div>
  );
}

// ── Root — handles auth routing ───────────────────────────────────────────────

function App() {
  const { user, login } = useUser();

  // Route guard: no user → auth page
  if (!user) {
    return <AuthPage onLogin={login} />;
  }

  return <Dashboard />;
}

export default App;
